import Decimal from 'decimal.js';

// PnL simétrico
const calcularPnL = (grossReturn: number, stakes: number[]): number => {
  const total = new Decimal(grossReturn);
  const custos = stakes.reduce((acc, s) => acc.plus(new Decimal(s)), new Decimal(0));
  return total.minus(custos).toDecimalPlaces(2).toNumber();
};

// Exemplo: 85 - (20 + 39) = 26.00 (não 25.999999...)
calcularPnL(85, [20, 39]); // → 26.00

